    "inlineSchema": "// This is your Prisma schema file,\n// learn more about it in the docs: https://pris.ly/d/prisma-schema\n\n// Looking for ways to speed up your queries, or scale easily with your serverless or edge functions?\n// Try Prisma Accelerate: https://pris.ly/cli/accelerate-init\n\ngenerator client {\n  provider = \"prisma-client\"\n  output   = \"../generated/prisma\"\n}\n\ndatasource db {\n  provider = \"postgresql\"\n}\n\nenum AttendanceStatus {\n  Present\n  Absent\n  HalfDay\n  Leave\n}\n\nenum SpareType {\n  Spare\n  Additive\n  Accessory\n}\n\nenum OrderType {\n  Sale\n  ReturnToServiceCenter\n  WarrantyAMC\n}\n\nmodel User {\n  id               String    @id @default(uuid())\n  name             String\n  email            String    @unique\n  phoneNumber      String\n  franchiseeName   String\n  gstin            String\n  password         String\n  resetToken       String?\n  resetTokenExpiry DateTime?\n  createdAt        DateTime  @default(now())\n}\n\nmodel Material {\n  id            String   @id @default(uuid())\n  materialCode  String   @unique\n  description   String\n  materialGroup String\n  createdAt     DateTime @default(now())\n\n  prices               MaterialPrice[]\n  invoiceItems         InvoiceItem[]\n  engineerStock        EngineerStock[]\n  saleOrders           SaleOrder[]\n  warrantyAmcOrders    WarrantyAmcOrder[]\n  returnToGodownOrders ReturnToGodownOrder[]\n  customerReturns      CustomerReturn[]\n  godownStock          GodownStock[]\n}\n\nmodel MaterialPrice {\n  id              String   @id @default(uuid())\n  conditionRecord String\n  conditionType   String\n  rate            Float\n  validFrom       DateTime\n  validTo         DateTime\n\n  materialId String\n  material   Material @relation(fields: [materialId], references: [id])\n\n  createdAt DateTime @default(now())\n}\n\nmodel Invoice {\n  id            String   @id @default(uuid())\n  invoiceNumber String   @unique\n  invoiceDate   DateTime\n  customerName  String\n  franchiseeId  String\n\n  createdAt DateTime @default(now())\n\n  items       InvoiceItem[]\n  godownStock GodownStock[]\n}\n\nmodel InvoiceItem {\n  id String @id @default(uuid())\n\n  invoiceId String\n  invoice   Invoice @relation(fields: [invoiceId], references: [id])\n\n  materialCode String\n  material     Material @relation(fields: [materialCode], references: [materialCode])\n\n  description String\n  hsn         String?\n  quantity    Float\n  uom         String\n  unitPrice   Float\n  totalAmount Float\n  cgst        Float\n  sgst        Float\n  spareType   SpareType?\n\n  createdAt DateTime @default(now())\n}\n\nmodel Engineer {\n  id             String  @id @default(uuid())\n  name           String\n  email          String  @unique\n  phoneNumber    String?\n  specialization String?\n  franchiseeId   String\n\n  createdAt DateTime @default(now())\n\n  assignedGoods EngineerStock[]\n  orders        Order[]\n  attendance    Attendance[]\n}\n\nmodel EngineerStock {\n  id String @id @default(uuid())\n\n  engineerId String\n  engineer   Engineer @relation(fields: [engineerId], references: [id])\n\n  materialCode String\n  material     Material @relation(fields: [materialCode], references: [materialCode])\n\n  quantity Float\n\n  createdAt DateTime @default(now())\n}\n\n// ─── Orders ──────────────────────────────────────────────────────────────────\n\nmodel Order {\n  id           String    @id @default(uuid())\n  orderType    OrderType\n  engineerId   String\n  engineer     Engineer  @relation(fields: [engineerId], references: [id])\n  franchiseeId String\n\n  createdAt DateTime @default(now())\n\n  saleOrder           SaleOrder?\n  warrantyAmcOrder    WarrantyAmcOrder?\n  returnToGodownOrder ReturnToGodownOrder?\n}\n\nmodel SaleOrder {\n  id      String @id @default(uuid())\n  orderId String @unique\n  order   Order  @relation(fields: [orderId], references: [id])\n\n  billNumber   String   @unique\n  dateOfSale   DateTime\n  ticketNumber String?\n  customerName String?\n\n  materialCode String\n  material     Material @relation(fields: [materialCode], references: [materialCode])\n\n  description String\n  quantity    Float\n  spareType   SpareType?\n  price       Float\n\n  createdAt DateTime @default(now())\n}\n\nmodel WarrantyAmcOrder {\n  id      String @id @default(uuid())\n  orderId String @unique\n  order   Order  @relation(fields: [orderId], references: [id])\n\n  ticketNumber String\n  customerName String\n  date         DateTime\n\n  materialCode String\n  material     Material @relation(fields: [materialCode], references: [materialCode])\n\n  description String\n  quantity    Float\n  spareType   SpareType?\n\n  createdAt DateTime @default(now())\n}\n\nmodel ReturnToGodownOrder {\n  id      String @id @default(uuid())\n  orderId String @unique\n  order   Order  @relation(fields: [orderId], references: [id])\n\n  referenceNumber String   @unique\n  date            DateTime\n\n  materialCode String\n  material     Material @relation(fields: [materialCode], references: [materialCode])\n\n  description String\n  quantity    Float\n\n  createdAt DateTime @default(now())\n}\n\n// ─── Customer Returns ─────────────────────────────────────────────────────────\n\nmodel CustomerReturn {\n  id           String   @id @default(uuid())\n  returnDate   DateTime\n  franchiseeId String\n\n  materialCode String\n  material     Material @relation(fields: [materialCode], references: [materialCode])\n\n  materialName String\n  quantity     Float\n  pricePerUnit Float\n  totalPrice   Float\n\n  remarks String?\n\n  createdAt DateTime @default(now())\n}\n\n// ─── AMC Contracts ────────────────────────────────────────────────────────────\n\nmodel AmcContract {\n  id           String   @id @default(uuid())\n  icrNumber    String   @unique\n  warrantyType String\n  price        Float\n  discount     Float?\n  totalPrice   Float\n  engineerName String\n  date         DateTime\n  franchiseeId String\n\n  createdAt DateTime @default(now())\n}\n\n// ─── Godown Stock ─────────────────────────────────────────────────────────────\n\nmodel GodownStock {\n  id           String @id @default(uuid())\n  franchiseeId String\n\n  materialCode String\n  material     Material @relation(fields: [materialCode], references: [materialCode])\n\n  description       String?\n  hsn               String?\n  uom               String?\n  goodQuantity      Float      @default(0)\n  defectiveQuantity Float      @default(0)\n  unitPrice         Float?\n  totalAmount       Float?\n  cgst              Float?\n  sgst              Float?\n  spareType         SpareType?\n\n  // null = manually added, set = came from an invoice\n  invoiceId String?\n  invoice   Invoice? @relation(fields: [invoiceId], references: [id])\n\n  notes String?\n\n  createdAt DateTime @default(now())\n  updatedAt DateTime @updatedAt\n}\n\n// ─── Attendance ───────────────────────────────────────────────────────────────\n\nmodel Attendance {\n  id           String           @id @default(uuid())\n  engineerId   String\n  engineer     Engineer         @relation(fields: [engineerId], references: [id])\n  franchiseeId String\n  date         DateTime         @db.Date\n  status       AttendanceStatus\n  notes        String?\n  createdAt    DateTime         @default(now())\n\n  @@unique([engineerId, date])\n}\n",
